VALUES
  ('judicial-57f41407-moex-00213', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2019年香港發生「反對逃犯條例修訂草案運動」，支持者以集會遊行、靜坐、唱歌、罷課、設置連儂牆、 堵塞道路幹道等行為向政府提出抗議，最後演變為警民激烈衝突，引發國際媒體關注。根據上述內容判斷， 該運動具備何種社會運動的特色？', '["示威群眾癱瘓交通道路的理由合理，屬於合法的表意自由", "這是一種本於良知的公民不服從運動，故毋須負法律責任", "支持者為一群具有共同理念的人，以實現民主自由為目標", "積極參與社會運動可以促進國家認同，中國政府樂觀其成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00214', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '國家是指由一群人在特定的領土內組織政府，經營共同生活，並且擁有主權的政治性團體。下列有關國家 組成要素的敘述，何者正確？', '["我國國籍取得採「屬地為主，屬人為輔」的折衷制", "一國之領土範圍包含領陸、領空及經濟海域", "主權對外有獨立性，能與他國建立平等外交關係", "政府的更替代表國家滅亡，亦影響該國之國際地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00215', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依據我國相關法律，有關我國民意代表的選舉制度，下列何者正確？', '["區域立法委員為單一選區絕對多數制", "直轄市議員為單一選區兩票制", "縣市議員為比例代表制", "原住民立法委員為複數選區單記不可讓渡投票制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00216', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '中央選舉委員會依法統籌辦理公職人員選舉、罷免及公民投票事務，為行政院所屬中央二級機關。下列敘 述何者正確？', '["中央選舉委員會獨立行使職權，為我國法定之獨立機關", "中央選舉委員會委員之選任，由各政黨依其於立法院所占席次比例決定", "立法委員選舉區之變更，應由中央選舉委員會秉於公正而自為決定", "中央選舉委員會委員，為求客觀公正決策，不得具備任何政黨黨籍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00217', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國歷任總統的對中政策，下列何者正確？', '["蔣中正總統：對國際發布「一法三公報」，並主張兩岸關係為「漢賊不兩立」", "李登輝總統：提出「告臺灣同胞書」，主張兩岸需在相互尊重的前提下互動", "陳水扁總統：曾提出「四不一沒有」、「一邊一國論」等對中政策", "馬英九總統：提出「新三不政策」，即「不接觸、不談判、不妥協」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00218', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '憲法是國家的根本大法，下列何者主要的職責之一，就是負責提出修憲案？', '["總統", "大法官", "立法委員", "法務部部長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00219', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '基於有權利即有救濟之原則，人民之訴訟權不因其身分而被剝奪。下列何者不具有訴訟權之主體地位，無 法提出法律救濟？', '["受刑人認為獄中管理措施嚴重侵害基本權利", "母親代理流產之胎兒控告醫師醫療疏失", "同學因冒用校長名義巡堂遭學校記大過", "公務人員就影響權益的不當公權力措施，經申訴、再申訴後，向法院請求救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00220', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依司法院釋字第567號解釋意旨，下列何者是人類文明之根源與言論自由之基礎，亦為憲法所欲保障最基 本之人性尊嚴，因此國家機關不得以任何理由或方式侵犯之？', '["思想自由", "居住自由", "參政自由", "人身自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00221', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何者不是分散型違憲審查的優點？', '["由專門的違憲審查機關從事違憲審查，可統一法律見解", "人民可即時獲得救濟，無須用盡訴訟救濟程序", "各級法院皆擁有違憲審查權，較有助於建立法官的憲法意識", "終審法院原為審級制度的一環，不生第四審的疑慮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00222', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '負有公法上金錢給付義務之人民逾期不履行時，依法由下列那個機關就其財產逕為執行？', '["地方法院民事執行處", "法務部地方檢察署", "司法院司法行政廳", "法務部行政執行署"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
